#include "ca6k_00050_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k00050CustomTilingData tiling;
    const gert::RuntimeAttrs *attrs = context->GetAttrs();

    // Use GetOriginShape() to access dims (StorageShape does not have GetDim)
    auto xShape = context->GetInputShape(0)->GetOriginShape();
    uint32_t nDim = static_cast<uint32_t>(xShape.GetDim(0));
    uint32_t cInDim = static_cast<uint32_t>(xShape.GetDim(1));
    uint32_t hDim = static_cast<uint32_t>(xShape.GetDim(2));
    uint32_t wDim = static_cast<uint32_t>(xShape.GetDim(3));

    auto wShape = context->GetInputShape(1)->GetOriginShape();
    uint32_t outCDim = static_cast<uint32_t>(wShape.GetDim(0));
    uint32_t kHDim = static_cast<uint32_t>(wShape.GetDim(2));
    uint32_t kWDim = static_cast<uint32_t>(wShape.GetDim(3));

    const int32_t* stridePtr = attrs->GetAttrPointer<int32_t>(0);
    uint32_t strideVal = static_cast<uint32_t>(*stridePtr);

    const int32_t* padPtr = attrs->GetAttrPointer<int32_t>(1);
    uint32_t padHVal = static_cast<uint32_t>(padPtr[0]);
    uint32_t padWVal = static_cast<uint32_t>(padPtr[1]);

    const int32_t* dilPtr = attrs->GetAttrPointer<int32_t>(2);
    uint32_t dilHVal = static_cast<uint32_t>(dilPtr[0]);
    uint32_t dilWVal = static_cast<uint32_t>(dilPtr[1]);

    uint32_t outHDim = (hDim + 2 * padHVal - dilHVal * (kHDim - 1) - 1) / strideVal + 1;
    uint32_t outWDim = (wDim + 2 * padWVal - dilWVal * (kWDim - 1) - 1) / strideVal + 1;

    tiling.set_nDim(nDim);
    tiling.set_cInDim(cInDim);
    tiling.set_hDim(hDim);
    tiling.set_wDim(wDim);
    tiling.set_outHDim(outHDim);
    tiling.set_outWDim(outWDim);
    tiling.set_outCDim(outCDim);
    tiling.set_kHDim(kHDim);
    tiling.set_kWDim(kWDim);
    tiling.set_strideVal(strideVal);
    tiling.set_padHVal(padHVal);
    tiling.set_padWVal(padWVal);
    tiling.set_dilHVal(dilHVal);
    tiling.set_dilWVal(dilWVal);
    tiling.set_blockDim(8);
    tiling.set_tileCount(1);

    context->SetBlockDim(8);
    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t* currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

