static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    auto xShape = context->GetInputShape(0)->GetOriginShape();
    uint32_t n = static_cast<uint32_t>(xShape.GetDim(0));
    uint32_t h = static_cast<uint32_t>(xShape.GetDim(2));
    uint32_t w = static_cast<uint32_t>(xShape.GetDim(3));

    auto wShape = context->GetInputShape(1)->GetOriginShape();
    uint32_t outC = static_cast<uint32_t>(wShape.GetDim(0));
    uint32_t kH = static_cast<uint32_t>(wShape.GetDim(2));
    uint32_t kW = static_cast<uint32_t>(wShape.GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t* stridePtr = attrs->GetAttrPointer<int32_t>(0);
    int32_t stride = *stridePtr;

    const int32_t* padPtr = attrs->GetAttrPointer<int32_t>(1);
    int32_t padH = padPtr[0], padW = padPtr[1];

    const int32_t* dilPtr = attrs->GetAttrPointer<int32_t>(2);
    int32_t dilH = dilPtr[0], dilW = dilPtr[1];

    uint32_t outH = (h + 2 * padH - dilH * (kH - 1) - 1) / stride + 1;
    uint32_t outW = (w + 2 * padW - dilW * (kW - 1) - 1) / stride + 1;

    gert::Shape *yShape = context->GetOutputShape(0);
    yShape->SetDim(0, static_cast<int64_t>(n));
    yShape->SetDim(1, static_cast<int64_t>(outC));
    yShape->SetDim(2, static_cast<int64_t>(outH));
    yShape->SetDim(3, static_cast<int64_t>(outW));
    return GRAPH_SUCCESS;
}

